                const rawHeader = rows[0];
                const rawSeparator = rows[1];
                const rawBody = rows.slice(2);
                const headRowToken = {};
                headRowToken.type = TokenType.TABLE_HEAD_ROW;
                headRowToken.value = rawHeader;
                headRowToken.row = rawHeader;
