                    inlineCodeToken.type = TokenType.CODE_INLINE;
                    inlineCodeToken.value = match[1];
                    node.children.push({
                        type: TokenType.CODE_INLINE,
                        token: inlineCodeToken,
                        raw: match[0],
                        children: []
                    });
                    node.raw = node.raw.slice(match[0].length);
                    continue;
